
















// TRK-233: ESM dist-bundle chunk order is non-deterministic;
// `styles` may be undefined when this module evaluates
// (the path `entry → tenant-manager.jsx → GroupSidebar.jsx` doesn't
// guarantee styles.js evaluates first under esbuild's chunk
// allocation). Import the canonical ESM export.
//
// History: PR-2d's `const styles = window.__styles;` worked under
// Babel-standalone (the legacy jsx-loader runtime) because the
// indirect-eval frame leaked `const styles` to global scope. TD-030z
// retired that runtime and TRK-230z removed the registration, so the
// ESM import below is the only correct path.
import { styles } from '../styles.js';

import { useState } from "react";  // TRK-233 ESM import

// TRK-233: `t` was previously read as a bare ambient global (jsx-loader
// leaks `t` at host-page level in the browser/dist path). That made the
// component ReferenceError the moment it's actually rendered under a
// non-leaking runtime (Vitest, or any stricter bundler) — the same
// chunk-/scope-fragility class the `styles` import above fixed. Declare
// it the same way every sibling component does (TenantCard /
// SavedViewsPanel / CustomAlertsModal): prefer the registered helper,
// fall back to English. Behavior identical in the browser.
const t = window.__t || ((zh, en) => en);

function GroupSidebar({ groups, activeGroupId, onSelectGroup, onCreateGroup, onDeleteGroup, canWrite }) {
  const [showCreate, setShowCreate] = useState(false);
  const [newGroupId, setNewGroupId] = useState('');
  const [newGroupLabel, setNewGroupLabel] = useState('');

  const handleCreate = () => {
    if (newGroupId && newGroupLabel) {
      onCreateGroup({ id: newGroupId.toLowerCase().replace(/\s+/g, '-'), label: newGroupLabel });
      setNewGroupId('');
      setNewGroupLabel('');
      setShowCreate(false);
    }
  };

  const groupEntries = Object.entries(groups);

  return (
    <div style={styles.sidebar} role="complementary" aria-label={t('群組管理側欄', 'Group management sidebar')} aria-live="polite" aria-atomic="true">
      <div style={styles.sidebarTitle}>
        <span>{t('群組', 'Groups')} ({groupEntries.length})</span>
        {canWrite && (
          <button
            onClick={() => setShowCreate(!showCreate)}
            style={{ ...styles.button, ...styles.buttonSmall }}
            title={t('建立新群組 — 用於批量操作和分組篩選', 'Create new group — for batch operations and group filtering')}
            aria-label={showCreate ? t('取消建立群組', 'Cancel create group') : t('建立新群組', 'Create new group')}
            aria-expanded={showCreate}
          >
            {showCreate ? '−' : '+'}
          </button>
        )}
      </div>

      {showCreate && (
        <div style={{ marginBottom: 'var(--da-space-3)', padding: 'var(--da-space-2)', backgroundColor: 'var(--da-color-bg)', borderRadius: 'var(--da-radius-md)' }}>
          <label htmlFor="new-group-id" style={styles.formLabel}>{t('群組 ID', 'Group ID')}</label>
          <input
            id="new-group-id"
            style={styles.inputField}
            placeholder="e.g., production-dba"
            value={newGroupId}
            onChange={e => setNewGroupId(e.target.value)}
          />
          <label htmlFor="new-group-label" style={styles.formLabel}>{t('顯示名稱', 'Display Label')}</label>
          <input
            id="new-group-label"
            style={styles.inputField}
            placeholder="e.g., Production DBA"
            value={newGroupLabel}
            onChange={e => setNewGroupLabel(e.target.value)}
          />
          <button onClick={handleCreate} style={{ ...styles.button, ...styles.buttonSmall, width: '100%' }}>
            {t('建立群組', 'Create Group')}
          </button>
        </div>
      )}

      {/* "All Tenants" entry */}
      <div
        style={{
          ...styles.groupItem,
          ...(activeGroupId === null ? styles.groupItemActive : styles.groupItemDefault),
        }}
        role="button"
        tabIndex={0}
        aria-label={t('所有租戶', 'All Tenants')}
        aria-pressed={activeGroupId === null}
        onClick={() => onSelectGroup(null)}
        onKeyDown={e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); onSelectGroup(null); } }}
      >
        {t('所有租戶', 'All Tenants')}
      </div>

      {groupEntries.length === 0 && (
        <div style={styles.emptyState}>
          <div style={{ fontSize: 'var(--da-font-size-xl)', marginBottom: 'var(--da-space-2)' }} aria-hidden="true">📁</div>
          <div>{t('尚無群組', 'No groups yet')}</div>
          <div style={{ fontSize: 'var(--da-font-size-xs)', marginTop: 'var(--da-space-1)' }}>
            {t('建立群組以批量管理租戶', 'Create a group to batch-manage tenants')}
          </div>
        </div>
      )}

      {groupEntries.map(([id, group]) => (
        // a11y: outer row is NON-interactive (plain div); select + delete are
        // SIBLING <button>s. Was `<div role="button">` wrapping a nested
        // delete <button> → axe `nested-interactive` (WCAG 4.1.2) once this
        // sidebar started rendering. Native <button>s are keyboard-accessible
        // (drop the manual role/tabIndex/onKeyDown).
        <div
          key={id}
          style={{
            ...styles.groupItem,
            ...(activeGroupId === id ? styles.groupItemActive : styles.groupItemDefault),
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
          }}
        >
          <button
            type="button"
            aria-pressed={activeGroupId === id}
            aria-label={`${t('選擇群組', 'Select group')}: ${group.label || id}`}
            onClick={() => onSelectGroup(id)}
            style={{ flex: 1, minWidth: 0, display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: 'none', border: 'none', padding: 0, margin: 0, font: 'inherit', color: 'inherit', cursor: 'pointer', textAlign: 'left' }}
          >
            <span>
              {group.label || id}
              <span style={styles.groupMemberCount}>({(group.members || []).length})</span>
            </span>
          </button>
          {canWrite && (
            <button
              type="button"
              style={{ ...styles.chipClose, fontSize: 'var(--da-font-size-sm-md)', color: 'var(--da-color-muted)', background: 'none', border: 'none', cursor: 'pointer', padding: '2px 4px', marginLeft: 'var(--da-space-1)', flexShrink: 0 }}
              title={t('刪除此群組', 'Delete this group')}
              aria-label={`${t('刪除群組', 'Delete group')}: ${group.label || id}`}
              onClick={(e) => { e.stopPropagation(); onDeleteGroup(id); }}
            >
              ✕
            </button>
          )}
        </div>
      ))}
    </div>
  );
}

export { GroupSidebar };
